    "startTimeSec": 911.3026666666675,
    "startFrame": 27339,
    "durationSec": 4.021333333333334,
    "durationFrames": 121,
    "speaker": "ずんだもん",
    "text": "1つ、イノベーションは「発明」だけじゃないのだ。",
